B.ER=new A.fo("\u6211\u60f3\u6253\u5f00\u95e8\u770b\u770b\u3002\n\u5c31\u7b97\u5916\u9762\u53ef\u80fd\u4e0d\u597d\uff0c\u6211\u4e5f\u60f3\u81ea\u5df1\u786e\u8ba4\u3002","I want to open the door and see.\nEven if it's not great out there, I want to find out for myself.","\u4f60\u6709\u4e00\u79cd\u76f4\u89c9\u2014\u2014\u60f3\u4eb2\u773c\u770b\u770b\u771f\u76f8\u3002\n\u4e24\u5343\u591a\u5e74\u524d\uff0c\u6709\u4e00\u4e2a\u4eba\u628a\u4f60\u7684\u8fd9\u79cd\u76f4\u89c9\u53d8\u6210\u4e86\u54f2\u5b66\u53f2\u4e0a\u6700\u8457\u540d\u7684\u5bd3\u8a00\u3002","You have an instinct \u2014 to see the truth with your own eyes. \nOver two thousand years ago, someone turned that very instinct into the most famous allegory in philosophy.")
B.EU=new A.fo("\u6211\u4e3a\u4ec0\u4e48\u8981\u76f8\u4fe1\u4ed6\uff1f\n\u5c4f\u5e55\u4e0a\u7684\u4e16\u754c\u6211\u5df2\u7ecf\u5f88\u719f\u6089\u4e86\uff0c\u90a3\u5c31\u662f\u6211\u7684\u73b0\u5b9e\u3002","Why should I believe them?\nI'm already familiar with the world on screen \u2014 that IS my reality.","\u4f60\u9009\u62e9\u4e86\u4fe1\u4efb\u5df2\u6709\u7684\u7ecf\u9a8c\u3002\u4f46\u67cf\u62c9\u56fe\u4f1a\u95ee\u4f60\uff1a\u5982\u679c\u4f60\u7684\u5168\u90e8\u7ecf\u9a8c\u672c\u8eab\u5c31\u662f\u88ab\u8bbe\u8ba1\u7684\u5462\uff1f","You chose to trust your existing experience. But Plato would ask: what if your entire experience was designed?")
B.ET=new A.fo('\u5c31\u7b97\u5916\u9762\u6709"\u771f\u5b9e\u4e16\u754c"\uff0c\u90a3\u8ddf\u6211\u6709\u4ec0\u4e48\u5173\u7cfb\uff1f\n\u6211\u5728\u8fd9\u91cc\u6d3b\u5f97\u597d\u597d\u7684\u3002',"Even if there's a \"real world\" out there, what does that have to do with me?\nI'm doing just fine here.",'\u4f60\u89c9\u5f97"\u771f\u4e0d\u771f\u5b9e"\u4e0d\u91cd\u8981\uff0c\u8fc7\u5f97\u597d\u624d\u91cd\u8981\u3002\u67cf\u62c9\u56fe\u542c\u5230\u8fd9\u8bdd\uff0c\u5927\u6982\u4f1a\u53f9\u4e00\u53e3\u6c14\u2014\u2014\u7136\u540e\u7ed9\u4f60\u8bb2\u4e00\u4e2a\u6545\u4e8b\u3002','You think "real or not" doesn\'t matter \u2014 what matters is living well. Plato would probably sigh at this \u2014 and then tell you a story.')
B.HI=A.a(s([B.ER,B.EU,B.ET]),t.t2)
B.Wg=new A.zC(null,null,"\u60f3\u8c61\u8fd9\u6837\u4e00\u4e2a\u573a\u666f\uff1a\u5047\u8bbe\u4f60\u4ece\u51fa\u751f\u8d77\u5c31\u53ea\u901a\u8fc7\u4e00\u5757\u5c4f\u5e55\u4e86\u89e3\u4e16\u754c\uff0c\u4f60\u770b\u5230\u7684\u4e00\u5207\u90fd\u5408\u7406\u3001\u81ea\u6d3d\u3001\u6ca1\u6709\u7834\u7efd\u3002\n\n\u6709\u4e00\u5929\u6709\u4eba\u544a\u8bc9\u4f60\uff1a\u5c4f\u5e55\u5916\u9762\u8fd8\u6709\u4e00\u4e2a\u5b8c\u5168\u4e0d\u540c\u7684\u4e16\u754c\u3002","Imagine this: Suppose that since birth, you've only known the world through a screen. Everything you see is consistent, logical, and flawless.\n\nOne day, someone tells you: there's an entirely different world beyond the screen.",B.HI,'\u4e24\u5343\u591a\u5e74\u524d\uff0c\u67cf\u62c9\u56fe\u8bb2\u4e86\u4e00\u4e2a\u51e0\u4e4e\u4e00\u6837\u7684\u6545\u4e8b\u2014\u2014\u6709\u4e9b\u4eba\u4ece\u51fa\u751f\u8d77\u5c31\u88ab\u9501\u5728\u4e00\u4e2a\u6d1e\u7a74\u91cc\uff0c\u628a\u5899\u4e0a\u7684\u5f71\u5b50\u5f53\u6210\u4e86\u5168\u90e8\u7684\u73b0\u5b9e\u3002\u4ed6\u7ba1\u8fd9\u4e2a\u53eb"\u6d1e\u7a74\u5bd3\u8a00"\u3002','Over two thousand years ago, Plato told an almost identical story \u2014 some people were chained in a cave from birth, mistaking shadows on the wall for all of reality. He called it "The Allegory of the Cave."')
B.Re=new A.dZ("\u67cf\u62c9\u56fe\u8bf4\uff1a\u60f3\u8c61\u4e00\u4e2a\u5730\u4e0b\u6d1e\u7a74\u3002\u4e00\u7fa4\u4eba\u4ece\u51fa\u751f\u8d77\u5c31\u88ab\u9501\u5728\u91cc\u9762\uff0c\u4ed6\u4eec\u7684\u5934\u88ab\u56fa\u5b9a\u4f4f\uff0c\u53ea\u80fd\u770b\u7740\u524d\u9762\u7684\u5899\u58c1\u3002\u5728\u4ed6\u4eec\u8eab\u540e\u6709\u4e00\u5806\u706b\uff0c\u706b\u548c\u4ed6\u4eec\u4e4b\u95f4\u6709\u4e00\u6761\u8d70\u9053\uff0c\u8d70\u9053\u4e0a\u6709\u4eba\u4e3e\u7740\u5404\u79cd\u4e1c\u897f\u8d70\u8fc7\u2014\u2014\u52a8\u7269\u3001\u5668\u5177\u3001\u4eba\u5f62\u3002\u706b\u5149\u628a\u8fd9\u4e9b\u4e1c\u897f\u7684\u5f71\u5b50\u6295\u5728\u5899\u4e0a\u3002\n\n\u5bf9\u8fd9\u7fa4\u56da\u5f92\u6765\u8bf4\uff0c\u5899\u4e0a\u7684\u5f71\u5b50\u5c31\u662f\u4ed6\u4eec\u552f\u4e00\u7684\u73b0\u5b9e\u3002","Plato says: imagine an underground cave. A group of people have been chained inside since birth, their heads fixed so they can only face the wall ahead. Behind them burns a fire, and between the fire and the prisoners runs a walkway where others carry various objects \u2014 animals, tools, human figures. The firelight casts shadows of these objects onto the wall.\n\nFor these prisoners, the shadows on the wall are their only reality.","\u60f3\u8c61\u4f60\u4ece\u5c0f\u88ab\u56fa\u5b9a\u5728\u7535\u5f71\u9662\u5ea7\u4f4d\u4e0a\uff0c\u53ea\u80fd\u770b\u94f6\u5e55\uff0c\u4ece\u6765\u6ca1\u56de\u8fc7\u5934\uff0c\u4e5f\u4e0d\u77e5\u9053\u8eab\u540e\u6709\u653e\u6620\u673a\u3002\u94f6\u5e55\u4e0a\u7684\u753b\u9762\u5c31\u662f\u4f60\u8ba4\u8bc6\u7684\u5168\u90e8\u4e16\u754c\u3002","Imagine being strapped to a cinema seat since birth, only able to watch the screen, never turning around, never knowing there's a projector behind you. The images on screen are your entire known world.")
B.Ri=new A.dZ('\u56da\u5f92\u4eec\u751a\u81f3\u7ed9\u5f71\u5b50\u8d77\u540d\u5b57\uff0c\u8ba8\u8bba\u54ea\u4e2a\u5f71\u5b50\u4f1a\u5148\u51fa\u73b0\u3001\u4ee5\u4ec0\u4e48\u987a\u5e8f\u51fa\u73b0\u3002\u8c01\u731c\u5f97\u6700\u51c6\uff0c\u8c01\u5c31\u88ab\u8ba4\u4e3a\u6700\u806a\u660e\u3002\u5728\u4ed6\u4eec\u7684\u4e16\u754c\u91cc\uff0c"\u806a\u660e"\u5c31\u662f\u6700\u64c5\u957f\u9884\u6d4b\u5f71\u5b50\u7684\u4eba\u3002','The prisoners even name the shadows, discussing which shadow appears first and in what order. Whoever guesses most accurately is considered the wisest. In their world, "intelligence" means being best at predicting shadows.',"\u5c31\u50cf\u5982\u679c\u4f60\u4ece\u5c0f\u53ea\u901a\u8fc7\u77ed\u89c6\u9891\u4e86\u89e3\u67d0\u4e2a\u56fd\u5bb6\uff0c\u4f60\u4f1a\u4ee5\u4e3a\u90a3\u4e9b\u7247\u6bb5\u5c31\u662f\u90a3\u4e2a\u56fd\u5bb6\u7684\u5168\u8c8c\u3002\u4f60\u4e0d\u662f\u88ab\u9a97\u4e86\uff0c\u4f60\u53ea\u662f\u4ece\u6765\u6ca1\u6709\u673a\u4f1a\u770b\u5230\u5b8c\u6574\u7684\u73b0\u5b9e\u3002","It's like if you only knew a country through short videos since childhood \u2014 you'd think those clips were the full picture. You weren't deceived; you simply never had the chance to see the complete reality.")
B.Rk=new A.dZ("\u6709\u4e00\u5929\uff0c\u4e00\u4e2a\u56da\u5f92\u88ab\u677e\u5f00\u4e86\u9501\u94fe\u3002\u4ed6\u8f6c\u8fc7\u5934\uff0c\u770b\u5230\u4e86\u706b\u3002\u706b\u5149\u523a\u5f97\u4ed6\u7741\u4e0d\u5f00\u773c\u3002\u4ed6\u53c8\u88ab\u62c9\u5411\u6d1e\u53e3\u2014\u2014\u9633\u5149\u66f4\u52a0\u523a\u773c\uff0c\u4ed6\u51e0\u4e4e\u4ec0\u4e48\u90fd\u770b\u4e0d\u89c1\uff0c\u75db\u82e6\u4e0d\u582a\u3002\n\n\u771f\u76f8\u7684\u7b2c\u4e00\u4e2a\u7279\u5f81\uff1a\u5b83\u8ba9\u4eba\u4e0d\u8212\u670d\u3002","One day, a prisoner is unchained. He turns around and sees the fire. The light burns his eyes. He's then dragged toward the cave entrance \u2014 the sunlight is even more blinding, and he can barely see anything. It's painful.\n\nThe first characteristic of truth: it's uncomfortable.",'\u4e3a\u4ec0\u4e48\u771f\u76f8\u8ba9\u4eba\u4e0d\u8212\u670d\uff1f\u56e0\u4e3a\u63a5\u53d7\u771f\u76f8\u610f\u5473\u7740\u5426\u5b9a\u4f60\u4e4b\u524d\u5168\u90e8\u7684\u8ba4\u77e5\u3002\u4f60\u4ee5\u4e3a\u7684"\u4e16\u754c"\u7a81\u7136\u53d8\u6210\u4e86"\u5f71\u5b50"\u3002\u8fd9\u79cd\u51b2\u51fb\u4e0d\u4ec5\u662f\u7406\u667a\u4e0a\u7684\uff0c\u66f4\u662f\u60c5\u611f\u4e0a\u7684\u2014\u2014\u5c31\u50cf\u6709\u4eba\u544a\u8bc9\u4f60\uff0c\u4f60\u8bb0\u5fc6\u4e2d\u7684\u7ae5\u5e74\u5176\u5b9e\u4e0d\u662f\u90a3\u6837\u7684\u3002','Why is truth uncomfortable? Because accepting it means negating everything you previously knew. What you thought was "the world" suddenly becomes "just shadows." This shock isn\'t just intellectual \u2014 it\'s emotional. Like someone telling you your childhood memories aren\'t what you thought.')
B.Rp=new A.dZ('\u6162\u6162\u5730\uff0c\u4ed6\u7684\u773c\u775b\u9002\u5e94\u4e86\u3002\u4ed6\u5148\u770b\u5230\u6c34\u4e2d\u7684\u5012\u5f71\uff0c\u7136\u540e\u662f\u4e8b\u7269\u672c\u8eab\uff0c\u7136\u540e\u662f\u661f\u7a7a\uff0c\u6700\u540e\u2014\u2014\u4ed6\u76f4\u89c6\u4e86\u592a\u9633\u3002\n\n\u67cf\u62c9\u56fe\u8bf4\uff0c\u592a\u9633\u5c31\u662f"\u5584\u7684\u7406\u5ff5"\uff08the Form of the Good\uff09\u2014\u2014\u6240\u6709\u771f\u7406\u548c\u5b58\u5728\u7684\u7ec8\u6781\u6e90\u5934\u3002\u770b\u5230\u592a\u9633\u7684\u90a3\u4e2a\u77ac\u95f4\uff0c\u4ed6\u7406\u89e3\u4e86\u4e00\u5207\uff1a\u5f71\u5b50\u3001\u706b\u5149\u3001\u6d1e\u7a74\u2014\u2014\u5b83\u4eec\u5728\u6574\u4e2a\u79e9\u5e8f\u4e2d\u5404\u81ea\u7684\u4f4d\u7f6e\u3002',"Gradually, his eyes adjust. First he sees reflections in water, then things themselves, then the stars, and finally \u2014 he looks directly at the sun.\n\nPlato says the sun represents the Form of the Good \u2014 the ultimate source of all truth and existence. In that moment of seeing the sun, he understands everything: the shadows, the firelight, the cave \u2014 each in its proper place within the grand order.",'\u67cf\u62c9\u56fe\u4e0d\u662f\u5728\u8bf4\u771f\u7684\u592a\u9633\u3002\u4ed6\u7528\u592a\u9633\u6765\u6bd4\u55bb\u4e00\u79cd\u7ec8\u6781\u7684\u771f\u7406\u2014\u2014\u5f53\u4f60\u7406\u89e3\u4e86\u5b83\uff0c\u5176\u4ed6\u6240\u6709\u4e8b\u60c5\u7a81\u7136\u90fd\u6709\u4e86\u610f\u4e49\u3002\u5c31\u50cf\u5b66\u6570\u5b66\u65f6\u7a81\u7136"\u5f00\u7a8d"\u7684\u90a3\u4e2a\u77ac\u95f4\uff1a\u4e00\u4e2a\u6839\u672c\u6027\u7684\u539f\u7406\u8ba9\u6240\u6709\u7ec6\u8282\u5404\u5f52\u5176\u4f4d\u3002','Plato isn\'t talking about the literal sun. He uses it as a metaphor for ultimate truth \u2014 once you grasp it, everything else suddenly makes sense. Like that "aha" moment in math: one fundamental principle puts all the details in their proper place.')
B.Rh=new A.dZ('\u7136\u540e\uff0c\u4ed6\u56de\u5230\u4e86\u6d1e\u7a74\u3002\u4ed6\u8bd5\u56fe\u544a\u8bc9\u5176\u4ed6\u4eba\uff1a\u4f60\u4eec\u770b\u5230\u7684\u53ea\u662f\u5f71\u5b50\uff0c\u5916\u9762\u6709\u4e00\u4e2a\u771f\u5b9e\u5f97\u591a\u7684\u4e16\u754c\u3002\n\n\u5176\u4ed6\u56da\u5f92\u7684\u53cd\u5e94\uff1f\u4ed6\u4eec\u89c9\u5f97\u4ed6\u75af\u4e86\u3002\u4ed6\u7684\u773c\u775b\u5728\u9ed1\u6697\u4e2d\u770b\u4e0d\u6e05\u5f71\u5b50\u4e86\u2014\u2014\u4ed6\u4eec\u5632\u7b11\u4ed6\uff1a"\u4f60\u51fa\u53bb\u4e00\u8d9f\uff0c\u53cd\u800c\u53d8\u8822\u4e86\u3002"\u5982\u679c\u6709\u4eba\u8bd5\u56fe\u5e26\u4ed6\u4eec\u51fa\u53bb\uff0c\u4ed6\u4eec\u751a\u81f3\u4f1a\u6740\u4e86\u90a3\u4e2a\u4eba\u3002',"Then he returns to the cave. He tries to tell the others: what you see are merely shadows \u2014 there's a far more real world outside.\n\nThe other prisoners' reaction? They think he's gone mad. His eyes can no longer make out the shadows in the dark \u2014 they mock him: \"You went out and came back stupider.\" If anyone tried to lead them out, they would even kill that person.",'\u67cf\u62c9\u56fe\u5199\u8fd9\u6bb5\u8bdd\u65f6\uff0c\u5fc3\u4e2d\u60f3\u7684\u662f\u4ed6\u7684\u8001\u5e08\u82cf\u683c\u62c9\u5e95\u3002\u82cf\u683c\u62c9\u5e95\u5c31\u662f\u90a3\u4e2a"\u56de\u5230\u6d1e\u7a74"\u7684\u4eba\u2014\u2014\u4ed6\u8bd5\u56fe\u5524\u9192\u96c5\u5178\u4eba\u53bb\u601d\u8003\uff0c\u7ed3\u679c\u88ab\u6295\u7968\u5904\u6b7b\u4e86\u3002','When Plato wrote this, he was thinking of his teacher Socrates. Socrates was the one who "returned to the cave" \u2014 he tried to awaken Athenians to think, and was voted to death for it.')
B.Hw=A.a(s([B.Re,B.Ri,B.Rk,B.Rp,B.Rh]),t.C8)
B.z6=new A.jf("\u5dee\u4e0d\u591a\uff0c\u90fd\u662f\u88ab\u9650\u5236\u5728\u90e8\u5206\u771f\u76f8\u91cc","Pretty much \u2014 both limit you to partial truth")
B.z3=new A.jf("\u4e0d\u592a\u4e00\u6837\uff0c\u4fe1\u606f\u8327\u623f\u6211\u53ef\u4ee5\u4e3b\u52a8\u6253\u7834\uff0c\u4f46\u6d1e\u7a74\u91cc\u7684\u4eba\u6839\u672c\u4e0d\u77e5\u9053\u81ea\u5df1\u88ab\u56f0\u4f4f\u4e86","Not quite \u2014 I can actively break out of an information bubble, but cave prisoners don't even know they're trapped")
B.GO=A.a(s([B.z6,B.z3]),t.CT)
B.z7=new A.ED('\u4f60\u89c9\u5f97"\u4fe1\u606f\u8327\u623f"\u548c\u67cf\u62c9\u56fe\u7684\u6d1e\u7a74\u662f\u540c\u4e00\u56de\u4e8b\u5417\uff1f','Do you think the "information bubble" and Plato\'s cave are the same thing?',B.GO)
B.Rs=new A.zl('\u67cf\u62c9\u56fe\u51fa\u751f\u5728\u96c5\u5178\u7684\u8d35\u65cf\u5bb6\u5ead\uff0c\u5e74\u8f7b\u65f6\u8ddf\u968f\u82cf\u683c\u62c9\u5e95\u5b66\u4e60\u3002\u82cf\u683c\u62c9\u5e95\u56e0\u4e3a"\u8150\u8680\u9752\u5e74\u601d\u60f3"\u88ab\u6c11\u4e3b\u6295\u7968\u5224\u5904\u6b7b\u5211\uff0c\u8fd9\u4ef6\u4e8b\u6df1\u6df1\u9707\u52a8\u4e86\u67cf\u62c9\u56fe\u3002\u4ed6\u5f00\u59cb\u8ffd\u95ee\uff1a\u4e3a\u4ec0\u4e48\u5927\u591a\u6570\u4eba\u5b81\u613f\u76f8\u4fe1\u8868\u9762\u7684\u4e1c\u897f\uff0c\u4e5f\u4e0d\u613f\u8ffd\u5bfb\u771f\u76f8\uff1f','Plato was born into an aristocratic Athenian family and studied under Socrates in his youth. When Socrates was sentenced to death by democratic vote for "corrupting the youth," it profoundly shook Plato. He began to ask: why do most people prefer to believe what\'s on the surface rather than seek the truth?',B.Hw,"\u5927\u591a\u6570\u4eba\u4e00\u8f88\u5b50\u90fd\u5728\u770b\u5f71\u5b50\uff0c\u4ee5\u4e3a\u90a3\u5c31\u662f\u5168\u90e8\u771f\u5b9e\u3002\u8d70\u51fa\u6d1e\u7a74\u4e0d\u662f\u4e00\u4ef6\u5feb\u4e50\u7684\u4e8b\u2014\u2014\u5b83\u75db\u82e6\u3001\u5b64\u72ec\uff0c\u751a\u81f3\u5371\u9669\u3002\u4f46\u67cf\u62c9\u56fe\u8ba4\u4e3a\uff0c\u90a3\u662f\u4eba\u552f\u4e00\u503c\u5f97\u8fc7\u7684\u4eba\u751f\u3002","Most people spend their entire lives watching shadows, believing them to be all of reality. Leaving the cave isn't a joyful experience \u2014 it's painful, lonely, even dangerous. But Plato believed it's the only life worth living.",'\u60f3\u60f3\u4f60\u624b\u673a\u4e0a\u7684\u4fe1\u606f\u6d41\u3002\u7b97\u6cd5\u6839\u636e\u4f60\u8fc7\u53bb\u7684\u884c\u4e3a\uff0c\u63a8\u9001\u4f60"\u53ef\u80fd\u559c\u6b22"\u7684\u5185\u5bb9\u3002\u4f60\u770b\u5230\u7684\u4e16\u754c\u8d8a\u6765\u8d8a\u50cf\u4f60\u5df2\u7ecf\u76f8\u4fe1\u7684\u90a3\u4e2a\u6837\u5b50\u3002\u8fd9\u4e0d\u5c31\u662f\u4e00\u4e2a\u6570\u5b57\u7248\u7684\u6d1e\u7a74\u5417\uff1f\u4f60\u770b\u5230\u7684"\u4fe1\u606f"\u5c31\u662f\u5899\u4e0a\u7684\u5f71\u5b50\uff0c\u7b97\u6cd5\u5c31\u662f\u8eab\u540e\u7684\u706b\u5149\u548c\u64cd\u5076\u4eba\u3002','Think about the feed on your phone. Algorithms push content you "might like" based on your past behavior. The world you see increasingly resembles what you already believe. Isn\'t this a digital cave? The "information" you see are shadows on the wall, and the algorithm is the fire and puppet-masters behind you.',B.z7,'\u6d1e\u7a74\u5bd3\u8a00\u662f\u897f\u65b9\u54f2\u5b66\u53f2\u4e0a\u6700\u6709\u5f71\u54cd\u529b\u7684\u9690\u55bb\u4e4b\u4e00\u3002\u5b83\u5f71\u54cd\u4e86\u540e\u6765\u51e0\u4e4e\u6240\u6709\u5173\u4e8e"\u8868\u8c61\u4e0e\u771f\u5b9e"\u7684\u8ba8\u8bba\u2014\u2014\u4ece\u7b1b\u5361\u5c14\u7684\u6000\u7591\u8bba\uff0c\u5230\u300a\u9ed1\u5ba2\u5e1d\u56fd\u300b\u7684\u84dd\u8272\u836f\u4e38\u548c\u7ea2\u8272\u836f\u4e38\u3002\u67cf\u62c9\u56fe\u7528\u8fd9\u4e2a\u6545\u4e8b\u60f3\u544a\u8bc9\u4f60\uff1a\u54f2\u5b66\u4e0d\u662f\u8c61\u7259\u5854\u91cc\u7684\u6e38\u620f\uff0c\u5b83\u5173\u4e4e\u4f60\u5982\u4f55\u770b\u5f85\u81ea\u5df1\u7684\u6574\u4e2a\u4eba\u751f\u3002',"The Allegory of the Cave is one of the most influential metaphors in Western philosophy. It shaped nearly every subsequent discussion about appearance vs. reality \u2014 from Descartes' skepticism to The Matrix's blue pill and red pill. Plato used this story to tell you: philosophy isn't an ivory tower game \u2014 it's about how you see your entire life.")
B.CY=new A.aR("\u6211\u4f1a\u56de\u53bb\uff0c\u628a\u6211\u770b\u5230\u7684\u544a\u8bc9\u4ed6\u4eec\u3002","I'd go back and tell them what I saw.","node_2a")
B.D0=new A.aR("\u6211\u4e0d\u56de\u53bb\u4e86\u3002\u4ed6\u4eec\u4e0d\u4f1a\u4fe1\u6211\uff0c\u56de\u53bb\u4e5f\u6ca1\u7528\u3002","I wouldn't go back. They won't believe me \u2014 it's pointless.","node_2b")
B.CZ=new A.aR('\u6211\u4f1a\u56de\u53bb\uff0c\u4f46\u4e0d\u662f\u7528"\u544a\u8bc9"\u7684\u65b9\u5f0f\u2014\u2014\u6211\u8981\u60f3\u529e\u6cd5\u8ba9\u4ed6\u4eec\u81ea\u5df1\u8d70\u51fa\u6765\u3002',"I'd go back, but not by \"telling\" them \u2014 I'd find a way to help them walk out themselves.","node_2c")
B.J1=A.a(s([B.CY,B.D0,B.CZ]),t.u)
B.Du=new A.bd("node_1","philosopher","\u6765\uff0c\u6211\u518d\u7ed9\u4f60\u8bb2\u4e00\u4e2a\u7248\u672c\u3002\u5047\u5982\u4f60\u5c31\u662f\u90a3\u4e2a\u8d70\u51fa\u6d1e\u7a74\u7684\u4eba\u3002\u4f60\u770b\u5230\u4e86\u9633\u5149\uff0c\u770b\u5230\u4e86\u771f\u5b9e\u7684\u4e16\u754c\u3002\u73b0\u5728\u4f60\u7ad9\u5728\u6d1e\u53e3\uff0c\u5f80\u56de\u770b\u3002\u91cc\u9762\u9ed1\u6d1e\u6d1e\u7684\uff0c\u4f60\u80fd\u542c\u5230\u4f60\u7684\u670b\u53cb\u4eec\u8fd8\u5728\u8ba8\u8bba\u5f71\u5b50\u3002\u4f60\u4f1a\u600e\u4e48\u505a\uff1f","Come, let me tell you another version. Suppose you are the one who left the cave. You've seen the sunlight, seen the real world. Now you stand at the cave entrance, looking back. It's dark inside, and you can hear your friends still debating shadows. What would you do?",B.J1,null,!1)
B.Ch=new A.aR("\u7ee7\u7eed\u8bf4\uff0c\u603b\u6709\u4eba\u4f1a\u542c\u7684\u3002","Keep talking \u2014 someone will listen eventually.","node_3")
B.Cp=new A.aR('\u4e5f\u8bb8\u6211\u8be5\u6362\u4e2a\u65b9\u5f0f\uff0c\u4e0d\u76f4\u63a5\u544a\u8bc9\u4ed6\u4eec"\u771f\u76f8"\uff0c\u800c\u662f\u5148\u8ba9\u4ed6\u4eec\u5bf9\u5f71\u5b50\u4ea7\u751f\u6000\u7591\u3002','Maybe I should change my approach \u2014 instead of telling them "the truth," first make them doubt the shadows.',"node_3")
B.GH=A.a(s([B.Ch,B.Cp]),t.u)
B.DM=new A.bd("node_2a","philosopher",'\u597d\u3002\u4f60\u56de\u53bb\u4e86\u3002\u4f60\u8ddf\u4ed6\u4eec\u8bf4\uff1a"\u4f60\u4eec\u770b\u5230\u7684\u662f\u5f71\u5b50\uff0c\u4e0d\u662f\u771f\u7684\u3002\u5916\u9762\u6709\u592a\u9633\u3001\u6709\u6811\u3001\u6709\u771f\u5b9e\u7684\u989c\u8272\u3002"\u4ed6\u4eec\u76ef\u7740\u4f60\u770b\u4e86\u4e00\u4f1a\u513f\uff0c\u7136\u540e\u7b11\u4e86\uff1a"\u4f60\u51fa\u53bb\u4e00\u8d9f\uff0c\u8fde\u5f71\u5b50\u90fd\u770b\u4e0d\u6e05\u4e86\u3002"\u6ca1\u6709\u4eba\u76f8\u4fe1\u4f60\u3002\u4f60\u600e\u4e48\u529e\uff1f','Good. You went back. You told them: "What you see are shadows, not real. Outside there\'s sun, trees, real colors." They stared at you for a moment, then laughed: "You went out and can\'t even see the shadows anymore." Nobody believes you. What now?',B.GH,null,!1)
B.Cz=new A.aR("\u6211\u53ef\u4ee5\u81ea\u5df1\u8fc7\u597d\u81ea\u5df1\u7684\u751f\u6d3b\u3002\u6bcf\u4e2a\u4eba\u90fd\u6709\u6743\u9009\u62e9\u81ea\u5df1\u7684\u4e16\u754c\u3002","I can live my own life well. Everyone has the right to choose their own world.","node_3")
B.CA=new A.aR("\u8bf4\u5b9e\u8bdd\uff0c\u4e0d\u592a\u5b89\u5fc3\u3002\u4f46\u6211\u5bb3\u6015\u56de\u53bb\u2014\u2014\u5bb3\u6015\u4ed6\u4eec\u4e0d\u7406\u89e3\u6211\uff0c\u5bb3\u6015\u518d\u6b21\u9677\u5165\u9ed1\u6697\u3002","Honestly, not really. But I'm afraid to go back \u2014 afraid they won't understand me, afraid of falling back into darkness.","node_3")
B.Ij=A.a(s([B.Cz,B.CA]),t.u)
B.Dn=new A.bd("node_2b","philosopher","\u4f60\u9009\u62e9\u7559\u5728\u9633\u5149\u4e0b\u3002\u6211\u7406\u89e3\u3002\u5916\u9762\u7684\u4e16\u754c\u7f8e\u6781\u4e86\u3002\u4f46\u662f\u2014\u2014\u4f60\u80fd\u5b89\u5fc3\u5417\uff1f\u4f60\u77e5\u9053\u4f60\u7684\u670b\u53cb\u4eec\u8fd8\u5728\u9ed1\u6697\u91cc\uff0c\u628a\u5f71\u5b50\u5f53\u6210\u5168\u90e8\u7684\u4eba\u751f\u3002\u4f60\u8f6c\u8fc7\u5934\u4e0d\u770b\uff0c\u5c31\u7b49\u4e8e\u90a3\u4e00\u5207\u4e0d\u5b58\u5728\u4e86\u5417\uff1f","You chose to stay in the sunlight. I understand. The outside world is beautiful. But \u2014 can you be at peace? You know your friends are still in the dark, taking shadows for the whole of life. If you turn away, does that make it all disappear?",B.Ij,null,!1)
B.Cx=new A.aR("\u4e5f\u8bb8\u53ef\u4ee5\u5148\u8ba9\u4ed6\u4eec\u6ce8\u610f\u5230\u5f71\u5b50\u6709\u65f6\u5019\u4e0d\u4e00\u81f4\u2014\u2014\u8ba9\u4ed6\u4eec\u81ea\u5df1\u4ea7\u751f\u6000\u7591\u3002","Maybe I can first help them notice that shadows sometimes don't match up \u2014 let them develop their own doubts.","node_3")
B.CP=new A.aR("\u4e5f\u8bb8\u8be5\u76f4\u63a5\u5e2e\u4ed6\u4eec\u89e3\u5f00\u9501\u94fe\uff0c\u5c31\u7b97\u4ed6\u4eec\u4e00\u5f00\u59cb\u4f1a\u6297\u62d2\u3002","Maybe I should just unchain them directly, even if they resist at first.","node_3")
B.Ib=A.a(s([B.Cx,B.CP]),t.u)
B.Dk=new A.bd("node_2c","philosopher",'\u6709\u610f\u601d\u3002\u4f60\u4e0d\u60f3"\u544a\u8bc9"\u4ed6\u4eec\u771f\u76f8\uff0c\u800c\u662f\u60f3\u5f15\u5bfc\u4ed6\u4eec\u3002\u4f46\u60f3\u60f3\u2014\u2014\u4ed6\u4eec\u8fde\u9501\u94fe\u90fd\u6ca1\u610f\u8bc6\u5230\u3002\u4f60\u6253\u7b97\u600e\u4e48\u8ba9\u4e00\u4e2a\u4e0d\u77e5\u9053\u81ea\u5df1\u88ab\u9501\u4f4f\u7684\u4eba\uff0c\u610f\u8bc6\u5230\u81ea\u5df1\u88ab\u9501\u4f4f\u4e86\uff1f',"Interesting. You don't want to \"tell\" them the truth \u2014 you want to guide them. But think: they don't even realize they're chained. How do you make someone who doesn't know they're bound realize they're bound?",B.Ib,null,!1)
B.Cy=new A.aR("\u5982\u679c\u6211\u8ba4\u4e3a\u771f\u76f8\u6bd4\u6211\u7684\u547d\u66f4\u91cd\u8981\u2014\u2014\u662f\u7684\u3002","If I believe truth is more important than my life \u2014 yes.","node_4a")
B.CC=new A.aR("\u4e0d\u503c\u5f97\u3002\u6b7b\u4e86\u5c31\u4ec0\u4e48\u90fd\u6ca1\u4e86\uff0c\u6d3b\u7740\u624d\u80fd\u5e2e\u66f4\u591a\u4eba\u3002","Not worth it. Dead means nothing \u2014 alive, I can help more people.","node_4b")
B.GJ=A.a(s([B.Cy,B.CC]),t.u)
B.Db=new A.bd("node_3","philosopher",'\u4f60\u77e5\u9053\u6211\u7684\u8001\u5e08\u82cf\u683c\u62c9\u5e95\u662f\u600e\u4e48\u505a\u7684\u5417\uff1f\u4ed6\u9009\u62e9\u4e86\u56de\u53bb\u3002\u4ed6\u8d70\u8fdb\u96c5\u5178\u7684\u8857\u5934\uff0c\u627e\u4eba\u5bf9\u8bdd\uff0c\u4e00\u4e2a\u95ee\u9898\u63a5\u4e00\u4e2a\u95ee\u9898\u5730\u8ffd\u95ee\uff0c\u76f4\u5230\u5bf9\u65b9\u53d1\u73b0\u81ea\u5df1\u5176\u5b9e\u4ec0\u4e48\u90fd\u4e0d\u77e5\u9053\u3002\u7ed3\u679c\u5462\uff1f\u4ed6\u4eec\u6295\u7968\u6740\u4e86\u4ed6\u3002\n\n\u6240\u4ee5\u6211\u95ee\u4f60\u4e00\u4e2a\u66f4\u96be\u7684\u95ee\u9898\uff1a\u5982\u679c\u4f60\u77e5\u9053"\u56de\u53bb"\u610f\u5473\u7740\u4f60\u53ef\u80fd\u4f1a\u6b7b\uff0c\u4f60\u8fd8\u56de\u53bb\u5417\uff1f','Do you know what my teacher Socrates did? He chose to go back. He walked into the streets of Athens, engaged people in dialogue, question after question, until they realized they knew nothing at all. The result? They voted to kill him.\n\nSo let me ask you a harder question: if you knew that "going back" might mean your death, would you still go?',B.GJ,null,!1)
B.DF=new A.bd("node_4a","philosopher",'\u82cf\u683c\u62c9\u5e95\u4e5f\u8fd9\u6837\u60f3\u3002\u4ed6\u8bf4\uff1a"\u672a\u7ecf\u5ba1\u89c6\u7684\u4eba\u751f\u4e0d\u503c\u5f97\u8fc7\u3002"\u5bf9\u4ed6\u6765\u8bf4\uff0c\u505c\u6b62\u8ffd\u95ee\u5c31\u7b49\u4e8e\u6b7b\u4e86\u2014\u2014\u6bd4\u8089\u4f53\u7684\u6b7b\u4ea1\u66f4\u53ef\u6015\u3002\n\n\u4f46\u6211\u6709\u65f6\u5019\u4f1a\u60f3\u2026\u2026\u4ed6\u7684\u59bb\u5b50\u548c\u5b69\u5b50\u600e\u4e48\u529e\uff1f\u662f\u4e0d\u662f\u5b58\u5728\u4e00\u79cd\u65b9\u5f0f\uff0c\u65e2\u5fe0\u4e8e\u771f\u7406\uff0c\u53c8\u4e0d\u5fc5\u6210\u4e3a\u6b89\u9053\u8005\uff1f','Socrates thought the same. He said: "The unexamined life is not worth living." For him, to stop questioning was already death \u2014 worse than physical death.\n\nBut sometimes I wonder... what about his wife and children? Is there a way to be faithful to truth without becoming a martyr?',null,"node_5",!1)
B.Dw=new A.bd("node_4b","philosopher",'\u4e5f\u8bb8\u4f60\u6bd4\u82cf\u683c\u62c9\u5e95\u66f4\u52a1\u5b9e\u3002\u6d3b\u7740\u786e\u5b9e\u80fd\u5e2e\u66f4\u591a\u4eba\u3002\u4f46\u8fd9\u91cc\u6709\u4e00\u4e2a\u9677\u9631\uff1a\u5f53\u4f60\u51b3\u5b9a"\u6682\u65f6\u4e0d\u8bf4\u771f\u8bdd"\u7684\u65f6\u5019\uff0c\u4f60\u4f1a\u4e0d\u4f1a\u6162\u6162\u4e60\u60ef\u6c89\u9ed8\uff1f\u5f53\u4f60\u5728\u9633\u5149\u548c\u6d1e\u7a74\u4e4b\u95f4\u6765\u56de\u8d70\u65f6\uff0c\u4f60\u4f1a\u4e0d\u4f1a\u5f00\u59cb\u5206\u4e0d\u6e05\u54ea\u4e2a\u624d\u662f\u4f60\u771f\u6b63\u7684\u4e16\u754c\uff1f',"Perhaps you're more pragmatic than Socrates. Staying alive does let you help more people. But here's a trap: when you decide to \"temporarily not speak the truth,\" might you slowly get used to silence? Moving back and forth between sunlight and cave, might you lose track of which is truly your world?",null,"node_5",!1)
B.Dd=new A.bd("node_5","philosopher","\u8fd9\u5c31\u662f\u6d1e\u7a74\u5bd3\u8a00\u771f\u6b63\u60f3\u8bf4\u7684\u4e8b\u3002\u5b83\u4e0d\u53ea\u662f\u4e00\u4e2a\u8ba4\u8bc6\u8bba\u7684\u5bd3\u8a00\u2014\u2014\u5b83\u662f\u4e00\u4e2a\u5173\u4e8e\u8d23\u4efb\u7684\u6545\u4e8b\u3002\n\n\u770b\u5230\u771f\u76f8\u7684\u4eba\uff0c\u8981\u4e0d\u8981\u56de\u53bb\uff1f\u56de\u53bb\u7684\u4ee3\u4ef7\u662f\u4ec0\u4e48\uff1f\u4e0d\u56de\u53bb\u7684\u4ee3\u4ef7\u53c8\u662f\u4ec0\u4e48\uff1f\n\n\u4e24\u5343\u591a\u5e74\u4e86\uff0c\u6ca1\u6709\u4eba\u80fd\u7ed9\u51fa\u4e00\u4e2a\u8ba9\u6240\u6709\u4eba\u6ee1\u610f\u7684\u7b54\u6848\u3002\u6b63\u56e0\u4e3a\u6ca1\u6709\u7b80\u5355\u7684\u7b54\u6848\uff0c\u8fd9\u4e2a\u95ee\u9898\u624d\u503c\u5f97\u6bcf\u4e00\u4ee3\u4eba\u91cd\u65b0\u53bb\u601d\u8003\u3002","This is what the Allegory of the Cave truly wants to say. It's not just an epistemological parable \u2014 it's a story about responsibility.\n\nShould those who've seen the truth go back? What's the cost of returning? What's the cost of not returning?\n\nFor over two thousand years, no one has given an answer that satisfies everyone. But Plato believed: precisely because there's no simple answer, this question deserves to be rethought by every generation.",null,null,!0)
B.IU=A.a(s([B.Du,B.DM,B.Dn,B.Dk,B.Db,B.DF,B.Dw,B.Dd]),t.WJ)
B.M8=new A.I4("Aristotle",'\u6211\u656c\u7231\u6211\u7684\u8001\u5e08\uff0c\u4f46\u6211\u66f4\u656c\u7231\u771f\u7406\u3002\u4ed6\u603b\u8bf4\u771f\u5b9e\u5728\u522b\u5904\u3001\u5728\u4ec0\u4e48"\u7406\u578b\u4e16\u754c"\u91cc\u3002\u53ef\u6211\u770b\u5230\u7684\u662f\uff1a\u771f\u5b9e\u5c31\u5728\u773c\u524d\u8fd9\u4e2a\u4e16\u754c\u7684\u6bcf\u4e00\u68f5\u6811\u3001\u6bcf\u4e00\u5757\u77f3\u5934\u91cc\u3002\u4e0e\u5176\u62c9\u4eba\u8d70\u51fa\u6d1e\u7a74\uff0c\u4e0d\u5982\u6559\u4ed6\u4eec\u7741\u5f00\u773c\u770b\u6e05\u773c\u524d\u7684\u4e1c\u897f\u3002','I love my teacher, but I love truth more. He always says reality is elsewhere, in some "world of Forms." But what I see is: reality is right here, in every tree and every stone before our eyes. Rather than dragging people out of caves, teach them to open their eyes to what\'s right in front of them.')
B.DP=new A.vC("node_1",B.IU,"\u4f60\u521a\u521a\u7ecf\u5386\u4e86\u4e00\u4e2a\u54f2\u5b66\u601d\u7ef4\u7684\u6838\u5fc3\u8fc7\u7a0b\uff1a\u4ece\u76f4\u89c9\u51fa\u53d1\uff0c\u901a\u8fc7\u4e0d\u65ad\u8ffd\u95ee\uff0c\u53d1\u73b0\u6bcf\u4e2a\u9009\u62e9\u90fd\u6709\u4ee3\u4ef7\u3002\u54f2\u5b66\u4e0d\u662f\u7ed9\u4f60\u7b54\u6848\u2014\u2014\u800c\u662f\u5e2e\u4f60\u770b\u6e05\u95ee\u9898\u7684\u5168\u8c8c\u3002","You just experienced a core process of philosophical thinking: starting from intuition, through relentless questioning, discovering that every choice has its cost. Philosophy doesn't give you answers \u2014 it helps you see the full picture of the question.",B.M8)
B.Oo=new A.hM("\u5e94\u8be5\u53bb\u62ef\u6551\uff0c\u653e\u4efb\u65e0\u77e5\u662f\u66f4\u5927\u7684\u4e0d\u8d1f\u8d23","We should try to save them \u2014 allowing ignorance is a greater irresponsibility")
B.Ol=new A.hM("\u8fd9\u672c\u8eab\u5c31\u662f\u50b2\u6162\uff0c\u6ca1\u4eba\u6709\u8d44\u683c\u66ff\u522b\u4eba\u5b9a\u4e49\u771f\u76f8","This is arrogance itself \u2014 no one has the right to define truth for others")
B.HY=A.a(s([B.Oo,B.Ol]),t.j3)
B.Or=new A.xQ('\u67cf\u62c9\u56fe\u8ba4\u4e3a\u770b\u5230\u771f\u76f8\u7684\u4eba\u6709\u8d23\u4efb\u56de\u53bb\u62ef\u6551\u6d1e\u7a74\u4e2d\u7684\u4eba\uff0c\u82cf\u683c\u62c9\u5e95\u4e3a\u6b64\u4ed8\u51fa\u4e86\u751f\u547d\u3002\u4f46\u4eca\u5929\u6211\u4eec\u8bf4\u8981"\u5c0a\u91cd\u6bcf\u4e2a\u4eba\u7684\u89c2\u70b9"\u3002\u4f60\u600e\u4e48\u770b\uff1f',"Plato believed those who've seen the truth have a duty to go back and save those in the cave. Socrates gave his life for this. But today we say we should \"respect everyone's viewpoint.\" What do you think?",B.HY)
B.NT=new A.b3("\u4eba\u4eec\u7684\u68a6\u5883","People's dreams")
B.NG=new A.b3("\u4eba\u4eec\u901a\u8fc7\u611f\u5b98\u63a5\u89e6\u5230\u7684\u8868\u8c61\u4e16\u754c","The world of appearances perceived through the senses")
B.Nn=new A.b3("\u54f2\u5b66\u5bb6\u7684\u7406\u8bba","Philosophers' theories")
B.Nb=new A.b3("\u53e4\u5e0c\u814a\u7684\u5b97\u6559\u4fe1\u4ef0","Ancient Greek religious beliefs")
B.HW=A.a(s([B.NT,B.NG,B.Nn,B.Nb]),t.l)
B.NX=new A.eE('\u5728\u6d1e\u7a74\u5bd3\u8a00\u4e2d\uff0c\u5899\u4e0a\u7684"\u5f71\u5b50"\u8c61\u5f81\u4ec0\u4e48\uff1f','In the Allegory of the Cave, what do the "shadows" on the wall symbolize?',B.HW,1,"\u5f71\u5b50\u4ee3\u8868\u6211\u4eec\u901a\u8fc7\u611f\u5b98\u611f\u77e5\u5230\u7684\u65e5\u5e38\u4e16\u754c\u2014\u2014\u67cf\u62c9\u56fe\u8ba4\u4e3a\u8fd9\u53ea\u662f\u771f\u5b9e\u4e16\u754c\u7684\u6295\u5f71\uff0c\u4e0d\u662f\u771f\u5b9e\u672c\u8eab\u3002","The shadows represent the everyday world we perceive through our senses \u2014 Plato believed this is merely a projection of the real world, not reality itself.")
B.Ng=new A.b3("\u77e5\u8bc6","Knowledge")
B.NA=new A.b3("\u81ea\u7531","Freedom")
B.NR=new A.b3("\u5584\u7684\u7406\u5ff5\uff08the Form of the Good\uff09","The Form of the Good")
B.NS=new A.b3("\u5b97\u6559\u4fe1\u4ef0\u4e2d\u7684\u795e","God in religious belief")
B.Hz=A.a(s([B.Ng,B.NA,B.NR,B.NS]),t.l)
B.O_=new A.eE('\u6d1e\u7a74\u5916\u9762\u7684"\u592a\u9633"\u5728\u67cf\u62c9\u56fe\u7684\u54f2\u5b66\u4e2d\u8c61\u5f81\u4ec0\u4e48\uff1f','What does the "sun" outside the cave symbolize in Plato\'s philosophy?',B.Hz,2,'\u592a\u9633\u8c61\u5f81"\u5584\u7684\u7406\u5ff5"\u2014\u2014\u67cf\u62c9\u56fe\u8ba4\u4e3a\u5b83\u662f\u6240\u6709\u771f\u7406\u548c\u5b58\u5728\u7684\u7ec8\u6781\u6e90\u5934\uff0c\u5c31\u50cf\u592a\u9633\u662f\u6240\u6709\u5149\u548c\u751f\u547d\u7684\u6e90\u5934\u3002',"The sun symbolizes the Form of the Good \u2014 Plato believed it is the ultimate source of all truth and existence, just as the sun is the source of all light and life.")
B.Nz=new A.b3("\u5d07\u62dc\u4ed6\uff0c\u5c0a\u4ed6\u4e3a\u9886\u8896","Worship him as a leader")
B.Ns=new A.b3("\u5632\u7b11\u4ed6\uff0c\u8ba4\u4e3a\u4ed6\u53d8\u8822\u4e86","Mock him, thinking he's become stupid")
B.Ni=new A.b3("\u597d\u5947\u5730\u8ddf\u4ed6\u4e00\u8d77\u51fa\u53bb","Curiously follow him outside")
B.Nq=new A.b3("\u51b7\u6de1\u65e0\u89c6","Coldly ignore him")
B.I2=A.a(s([B.Nz,B.Ns,B.Ni,B.Nq]),t.l)
B.O1=new A.eE("\u8d70\u51fa\u6d1e\u7a74\u7684\u56da\u5f92\u56de\u5230\u6d1e\u7a74\u540e\uff0c\u5176\u4ed6\u56da\u5f92\u5bf9\u4ed6\u7684\u6001\u5ea6\u662f\uff1f","When the freed prisoner returns to the cave, how do the other prisoners react?",B.I2,1,"\u5176\u4ed6\u56da\u5f92\u5632\u7b11\u4ed6\u2014\u2014\u56e0\u4e3a\u4ed6\u56de\u5230\u9ed1\u6697\u4e2d\u53cd\u800c\u770b\u4e0d\u6e05\u5f71\u5b50\u4e86\u3002\u67cf\u62c9\u56fe\u6697\u793a\uff1a\u8ffd\u6c42\u771f\u7406\u7684\u4eba\u5f80\u5f80\u4e0d\u88ab\u7406\u89e3\uff0c\u751a\u81f3\u88ab\u654c\u89c6\u3002\u82cf\u683c\u62c9\u5e95\u7684\u547d\u8fd0\u6b63\u662f\u5982\u6b64\u3002","The other prisoners mock him \u2014 because back in the dark, he can no longer see the shadows clearly. Plato implies: those who pursue truth are often misunderstood, even met with hostility. This was exactly Socrates' fate.")
B.NE=new A.b3("\u6279\u8bc4\u53e4\u5e0c\u814a\u7684\u653f\u6cbb\u5236\u5ea6","To criticize ancient Greek political systems")
B.NF=new A.b3("\u8bf4\u660e\u5927\u591a\u6570\u4eba\u751f\u6d3b\u5728\u8868\u8c61\u4e2d\uff0c\u771f\u6b63\u7684\u77e5\u8bc6\u9700\u8981\u8270\u82e6\u7684\u8ffd\u5bfb","To show that most people live among appearances, and true knowledge requires arduous pursuit")
B.NH=new A.b3("\u5ba3\u4f20\u5b97\u6559\u4fe1\u4ef0","To promote religious belief")
B.Ne=new A.b3("\u8bc1\u660e\u611f\u5b98\u7ecf\u9a8c\u5b8c\u5168\u4e0d\u53ef\u9760","To prove sensory experience is completely unreliable")
B.Ja=A.a(s([B.NE,B.NF,B.NH,B.Ne]),t.l)
B.NW=new A.eE("\u67cf\u62c9\u56fe\u5199\u6d1e\u7a74\u5bd3\u8a00\u7684\u6838\u5fc3\u76ee\u7684\u662f\u4ec0\u4e48\uff1f","What is the core purpose of Plato's Allegory of the Cave?",B.Ja,1,'\u6d1e\u7a74\u5bd3\u8a00\u7684\u6838\u5fc3\u662f\u8ba4\u8bc6\u8bba\uff1a\u6211\u4eec\u65e5\u5e38\u63a5\u89e6\u7684\u53ea\u662f"\u5f71\u5b50"\uff08\u8868\u8c61\uff09\uff0c\u771f\u6b63\u7684\u77e5\u8bc6\u9700\u8981\u8d70\u51fa\u8212\u9002\u533a\uff0c\u7ecf\u5386\u75db\u82e6\u7684\u601d\u8003\u8fc7\u7a0b\u624d\u80fd\u83b7\u5f97\u3002\u67cf\u62c9\u56fe\u4e0d\u662f\u8bf4\u611f\u5b98\u5b8c\u5168\u4e0d\u53ef\u9760\uff0c\u800c\u662f\u8bf4\u5b83\u4eec\u4e0d\u591f\u2014\u2014\u6211\u4eec\u9700\u8981\u7406\u6027\u53bb\u8ba4\u8bc6\u66f4\u6df1\u5c42\u7684\u771f\u5b9e\u3002',"The cave allegory is fundamentally about epistemology: our daily experience consists of \"shadows\" (appearances), and true knowledge requires stepping out of comfort zones and enduring painful thinking. Plato doesn't say senses are completely unreliable \u2014 just that they're insufficient. We need reason to grasp deeper reality.")
B.IO=A.a(s([B.NX,B.O_,B.O1,B.NW]),t.hB)
B.Gz=new A.ql("plato_cave","\u6d1e\u7a74\u5bd3\u8a00 \u2014 \u4f60\u770b\u5230\u7684\u662f\u771f\u5b9e\u7684\u5417\uff1f","The Allegory of the Cave \u2014 Is What You See Real?",B.Wg,B.Rs,B.DP,B.Or,B.IO)
B.EV=new A.fo("\u5e94\u8be5\uff0c\u5927\u90e8\u5206\u4eba\u7684\u9700\u6c42\u66f4\u91cd\u8981\u3002","Yes. The needs of the majority matter more.","\u4f60\u5c0a\u91cd\u591a\u6570\u4eba\u7684\u58f0\u97f3\u3002\u4f46\u67cf\u62c9\u56fe\u4f1a\u95ee\u4f60\uff1a\u5982\u679c\u591a\u6570\u4eba\u770b\u5230\u7684\u53ea\u662f\u5f71\u5b50\u5462\uff1f\u63a5\u4e0b\u6765\u770b\u770b\u67cf\u62c9\u56fe\u5982\u4f55\u628a\u6d1e\u7a74\u5bd3\u8a00\u53d8\u6210\u4e00\u5957\u653f\u6cbb\u4e3b\u5f20\u3002","You respect the voice of the majority. But Plato would ask: what if what the majority sees are merely shadows? Let's see how Plato turned the cave allegory into a political philosophy.")
B.EY=new A.fo("\u4e0d\u5e94\u8be5\uff0c\u5927\u4f17\u4e0d\u61c2\uff0c\u4e0d\u4ee3\u8868\u5b83\u6ca1\u4ef7\u503c\u3002","Don't change it. Just because the public doesn't understand it doesn't mean it has no value.","\u4f60\u89c9\u5f97\u6709\u4e9b\u4e1c\u897f\u7684\u4ef7\u503c\u4e0d\u8be5\u7531\u591a\u6570\u4eba\u51b3\u5b9a\u3002\u67cf\u62c9\u56fe\u4f1a\u975e\u5e38\u8d5e\u540c\u4f60\uff0c\u800c\u4e14\u4ed6\u66f4\u8fdb\u4e00\u6b65\uff1a\u4ed6\u8ba4\u4e3a\u6574\u4e2a\u57ce\u90a6\u7684\u6cbb\u7406\u90fd\u4e0d\u8be5\u7531\u591a\u6570\u4eba\u8bf4\u4e86\u7b97\u3002","You believe some things' value shouldn't be determined by the majority. Plato would strongly agree, and he goes further: he believed the entire governance of the city-state shouldn't be decided by the majority.")
B.Ic=A.a(s([B.EV,B.EY]),t.t2)
B.Wf=new A.zC("\u4f60\u89c9\u5f97\u5e94\u8be5\u62c6\u6389\u5546\u573a\u5417\uff1f","Do you think the mall should be demolished?","\u4e00\u4e2a\u57ce\u5e02\u82b1\u4e86\u5927\u94b1\u5efa\u4e86\u4e00\u5ea7\u73b0\u4ee3\u827a\u672f\u535a\u7269\u9986\u3002\u5f00\u9986\u4e00\u5e74\u540e\uff0c\u5927\u90e8\u5206\u5e02\u6c11\u89c9\u5f97\u770b\u4e0d\u61c2\uff0c\u8ba4\u4e3a\u6d6a\u8d39\u94b1\uff0c\u8981\u6c42\u62c6\u6389\u6539\u5efa\u5546\u573a\u3002","A city spent a fortune building a modern art museum. A year after opening, most residents find it incomprehensible, consider it a waste of money, and demand it be demolished and replaced with a shopping mall.",B.Ic,"","")
B.Ro=new A.dZ('\u67cf\u62c9\u56fe\u7684\u56de\u7b54\uff1a\u8ba9\u770b\u5230\u771f\u5b9e\u7684\u4eba\u6765\u7edf\u6cbb\u3002\u4ed6\u628a\u8fd9\u79cd\u4eba\u53eb\u505a"\u54f2\u5b66\u738b"\u3002\n\n\u54f2\u5b66\u738b\u4e0d\u662f\u806a\u660e\u4eba\uff0c\u4e0d\u662f\u4e13\u5bb6\uff0c\u4e0d\u662f\u6709\u7ecf\u9a8c\u7684\u957f\u8005\u3002\u67cf\u62c9\u56fe\u7684\u5b9a\u4e49\u975e\u5e38\u4e25\u683c\uff1a\u7ecf\u8fc7\u51e0\u5341\u5e74\u7cfb\u7edf\u8bad\u7ec3\uff0c\u6700\u7ec8\u8ba4\u8bc6\u4e86"\u5584"\u7684\u7406\u578b\u7684\u4eba\u3002\n\n\u4ed6\u8bbe\u8ba1\u4e86\u4e00\u5957\u5b8c\u6574\u7684\u6559\u80b2\u65b9\u6848\uff1a\u4ece\u97f3\u4e50\u4f53\u80b2\u5230\u6570\u5b66\u5929\u6587\uff0c\u6700\u540e\u662f\u8fa9\u8bc1\u6cd5\u3002\u5c42\u5c42\u7b5b\u9009\uff0c\u80fd\u8d70\u5230\u7ec8\u70b9\u7684\u6781\u5c11\u6570\u4eba\uff0c\u624d\u6709\u8d44\u683c\u7edf\u6cbb\u3002',"Plato's answer: let those who can see reality rule. He called such people \"philosopher kings.\"\n\nA philosopher king is not simply a smart person, an expert, or an experienced elder. Plato's definition is very strict: someone who has undergone decades of systematic training and ultimately grasped the Form of the Good.\n\nHe designed a complete educational program: from music and athletics to mathematics and astronomy, culminating in dialectics. Through layer upon layer of selection, only the very few who reach the end are qualified to rule.",'\u60f3\u8c61\u4e00\u7fa4\u4eba\u5728\u4e89\u8bba\u4e00\u9053\u6570\u5b66\u9898\u3002\u6709\u4eba\u731c3\uff0c\u6709\u4eba\u731c5\uff0c\u6709\u4eba\u8bf4\u6295\u7968\u51b3\u5b9a\u3002\u67cf\u62c9\u56fe\u4f1a\u8bf4\uff1a\u7b54\u6848\u5c31\u662f\u7b54\u6848\uff0c\u53ea\u6709\u771f\u6b63\u61c2\u6570\u5b66\u7684\u4eba\u77e5\u9053\u3002\u4ed6\u89c9\u5f97"\u4ec0\u4e48\u5bf9\u57ce\u90a6\u597d"\u4e5f\u4e00\u6837\uff0c\u4e0d\u662f\u89c2\u70b9\u4e4b\u4e89\uff0c\u6709\u5ba2\u89c2\u7684\u6b63\u786e\u7b54\u6848\uff0c\u53ea\u6709\u54f2\u5b66\u5bb6\u80fd\u770b\u5230\u3002',"Imagine a group arguing over a math problem. Someone guesses 3, another guesses 5, someone suggests voting on it. Plato would say: the answer is the answer \u2014 only someone who truly understands math knows it. He felt \"what's good for the city-state\" works the same way: it's not a matter of opinion, there's an objectively correct answer, and only philosophers can see it.")
B.Rd=new A.dZ("\u90a3\u666e\u901a\u4eba\u600e\u4e48\u529e\uff1f\n\n\u67cf\u62c9\u56fe\u628a\u57ce\u90a6\u5206\u4e09\u5c42\uff1a\u7edf\u6cbb\u8005\uff08\u54f2\u5b66\u738b\uff09\u9760\u667a\u6167\u51b3\u7b56\uff0c\u62a4\u536b\u8005\u9760\u52c7\u6c14\u4fdd\u536b\uff0c\u751f\u4ea7\u8005\u9760\u8282\u5236\u52b3\u4f5c\u3002\n\n\u6b63\u4e49\u5c31\u662f\u6bcf\u4e2a\u90e8\u5206\u505a\u597d\u81ea\u5df1\u7684\u4e8b\uff0c\u4e0d\u8d8a\u754c\u3002\u978b\u5320\u597d\u597d\u505a\u978b\uff0c\u4e0d\u8981\u60f3\u7740\u6cbb\u56fd\u3002\u54f2\u5b66\u5bb6\u4e13\u5fc3\u6cbb\u56fd\uff0c\u4e0d\u8981\u60f3\u7740\u7ecf\u5546\u3002\n\n\u4e2a\u4eba\u7075\u9b42\u4e5f\u4e00\u6837\uff1a\u7406\u6027\u3001\u610f\u5fd7\u3001\u6b32\u671b\uff0c\u4e09\u8005\u5404\u5b89\u5176\u4f4d\uff0c\u4eba\u5c31\u662f\u6b63\u4e49\u7684\u3002","So what about ordinary people?\n\nPlato divided the city-state into three layers: rulers (philosopher kings) who govern through wisdom, guardians who protect through courage, and producers who work through temperance.\n\nJustice means each part does its own job without overstepping. The shoemaker makes shoes well without thinking about ruling. The philosopher governs without thinking about commerce.\n\nThe individual soul works the same way: reason, spirit, and appetite \u2014 when each stays in its place, the person is just.",'\u5c31\u50cf\u4e00\u4e2a\u516c\u53f8\uff0c\u5b9e\u4e60\u751f\u5b9a\u6218\u7565\uff0cCEO\u626b\u5730\uff0c\u4e00\u5b9a\u4e71\u5957\u3002\u4e0d\u662f\u8c01\u66f4"\u9ad8\u7ea7"\uff0c\u800c\u662f\u6bcf\u4e2a\u4f4d\u7f6e\u9700\u8981\u4e0d\u540c\u80fd\u529b\uff0c\u786c\u6362\u5c31\u51fa\u95ee\u9898\u3002\u5f53\u7136\u6279\u8bc4\u8005\u4f1a\u95ee\uff1a\u8c01\u6765\u51b3\u5b9a\u4f60\u5c5e\u4e8e\u54ea\u4e2a\u9636\u5c42\uff1f\u4e07\u4e00\u5206\u9519\u4e86\u5462\uff1f',"It's like a company where the intern sets strategy and the CEO sweeps floors \u2014 chaos is guaranteed. It's not about who's \"higher rank,\" but that each position requires different abilities, and forcing a swap causes problems. Of course, critics would ask: who decides which class you belong to? What if they get it wrong?")
B.Rj=new A.dZ("\u6ce8\u610f\u67cf\u62c9\u56fe\u7684\u903b\u8f91\u94fe\uff1a\n\n\u5927\u591a\u6570\u4eba\u770b\u5230\u7684\u4e0d\u662f\u771f\u5b9e\uff08\u6d1e\u7a74\u5bd3\u8a00\uff09\u2192 \u5b58\u5728\u66f4\u9ad8\u7684\u771f\u5b9e\u4e16\u754c\uff08\u7406\u578b\u8bba\uff09\u2192 \u53ea\u6709\u5c11\u6570\u4eba\u80fd\u8ba4\u8bc6\u90a3\u4e2a\u4e16\u754c\uff08\u54f2\u5b66\u738b\uff09\u2192 \u5e94\u8be5\u7531\u8fd9\u4e9b\u5c11\u6570\u4eba\u6765\u7edf\u6cbb\uff08\u7406\u60f3\u56fd\uff09\n\n\u4e09\u8bfe\u7684\u5185\u5bb9\u5728\u8fd9\u91cc\u5408\u6210\u4e86\u5b8c\u6574\u4f53\u7cfb\u3002\u4ece\u8ba4\u8bc6\u8bba\u5230\u653f\u6cbb\u54f2\u5b66\uff0c\u67cf\u62c9\u56fe\u4e00\u6b65\u6b65\u63a8\u51fa\u4e86\u7ed3\u8bba\uff1a\u6c11\u4e3b\u662f\u5371\u9669\u7684\uff0c\u56e0\u4e3a\u5b83\u628a\u51b3\u5b9a\u6743\u4ea4\u7ed9\u4e86\u770b\u4e0d\u5230\u771f\u5b9e\u7684\u4eba\u3002","Notice Plato's chain of logic:\n\nMost people don't see reality (Allegory of the Cave) \u2192 A higher reality exists (Theory of Forms) \u2192 Only a few can perceive that world (philosopher kings) \u2192 These few should rule (The Republic)\n\nThe content of all three lessons comes together into a complete system. From epistemology to political philosophy, Plato builds his conclusion step by step: democracy is dangerous because it gives decision-making power to those who cannot see reality.",null,null)
B.Rf=new A.dZ("\u67cf\u62c9\u56fe\u4e0d\u662f\u5728\u4e66\u658b\u91cc\u7a7a\u60f3\u3002\u4ed6\u771f\u53bb\u8bd5\u4e86\u3002\n\n\u516c\u5143\u524d388\u5e74\u5de6\u53f3\uff0c\u4ed6\u524d\u5f80\u897f\u897f\u91cc\u5c9b\u7684\u53d9\u62c9\u53e4\u57ce\uff0c\u5e0c\u671b\u5f71\u54cd\u7edf\u6cbb\u8005\u3002\u4ed6\u53bb\u4e86\u4e09\u6b21\u3002\n\n\u7b2c\u4e00\u6b21\uff0c\u60f9\u6012\u4e86\u8001\u66b4\u541b\u72c4\u5965\u5c3c\u7d22\u65af\u4e00\u4e16\uff0c\u5dee\u70b9\u88ab\u5356\u4e3a\u5974\u96b6\u3002\u7b2c\u4e8c\u6b21\uff0c\u8001\u66b4\u541b\u6b7b\u4e86\uff0c\u4ed6\u53bb\u6559\u80b2\u5e74\u8f7b\u7684\u72c4\u5965\u5c3c\u7d22\u65af\u4e8c\u4e16\uff0c\u5e74\u8f7b\u66b4\u541b\u6839\u672c\u65e0\u5fc3\u5b66\u4e60\u3002\u7b2c\u4e09\u6b21\u518d\u53bb\uff0c\u518d\u6b21\u5931\u8d25\uff0c\u4e00\u5ea6\u88ab\u8f6f\u7981\u3002\n\n\u54f2\u5b66\u738b\u7684\u7406\u60f3\uff0c\u5728\u73b0\u5b9e\u9762\u524d\u5f7b\u5e95\u7c89\u788e\u4e86\u3002\n\n\u67cf\u62c9\u56fe\u665a\u5e74\u5199\u4e86\u300a\u6cd5\u5f8b\u7bc7\u300b\uff0c\u5f00\u59cb\u63a5\u53d7\u6cd5\u6cbb\u548c\u6df7\u5408\u653f\u4f53\u3002\u7b49\u4e8e\u9ed8\u8ba4\u4e86\uff1a\u627e\u4e0d\u5230\u54f2\u5b66\u738b\uff0c\u9000\u800c\u6c42\u5176\u6b21\uff0c\u9760\u5236\u5ea6\u7ea6\u675f\u3002","Plato wasn't just theorizing in his study. He actually tried it.\n\nAround 388 BC, he traveled to Syracuse in Sicily, hoping to influence the ruler. He went three times.\n\nThe first time, he angered the old tyrant Dionysius I and was nearly sold into slavery. The second time, the old tyrant had died, and he went to educate the young Dionysius II, who had no interest in learning. The third time, he failed again and was briefly placed under house arrest.\n\nThe ideal of the philosopher king was completely shattered in the face of reality.\n\nIn his later years, Plato wrote the Laws, accepting rule of law and mixed government. He essentially conceded: if you can't find a philosopher king, the next best thing is institutional constraints.",null,null)
B.Ii=A.a(s([B.Ro,B.Rd,B.Rj,B.Rf]),t.C8)
B.Rr=new A.zl("\u524d\u4e24\u8282\u8bfe\uff0c\u6211\u4eec\u53d1\u73b0\u4e86\u4e24\u4ef6\u4e8b\uff1a\n\n\u5927\u591a\u6570\u4eba\u6d3b\u5728\u6d1e\u7a74\u91cc\uff0c\u628a\u5f71\u5b50\u5f53\u771f\u5b9e\u3002\u800c\u771f\u6b63\u7684\u5b9e\u5728\uff0c\u662f\u6d1e\u7a74\u5916\u90a3\u4e2a\u5b8c\u7f8e\u7684\u7406\u578b\u4e16\u754c\u3002\n\n\u73b0\u5728\u67cf\u62c9\u56fe\u8981\u518d\u5f80\u524d\u4e00\u6b65\u3002\u65e2\u7136\u5927\u591a\u6570\u4eba\u770b\u4e0d\u5230\u771f\u5b9e\uff0c\u90a3\uff1a\n\n\u8c01\u6765\u505a\u51b3\u5b9a\uff1f","In the previous two lessons, we discovered two things:\n\nMost people live in the cave, mistaking shadows for reality. The true reality is the perfect world of Forms outside the cave.\n\nNow Plato takes one step further. Since most people can't see reality, then:\n\nWho gets to make the decisions?",B.Ii,"","","\u54f2\u5b66\u738b\u542c\u8d77\u6765\u867d\u7136\u5f88\u9065\u8fdc\uff0c\u4f46\u8fd9\u4e9b\u95ee\u9898\u4eca\u5929\u4f9d\u7136\u5b58\u5728\u3002\n\n\u6c14\u5019\u79d1\u5b66\u5bb6\u8bf4\u5fc5\u987b\u51cf\u6392\uff0c\u9009\u6c11\u4e0d\u613f\u627f\u62c5\u7ecf\u6d4e\u4ee3\u4ef7\u3002\u516c\u5171\u536b\u751f\u4e13\u5bb6\u8bf4\u5fc5\u987b\u5c01\u63a7\uff0c\u5e02\u6c11\u53cd\u5bf9\u9650\u5236\u81ea\u7531\u3002\u7ecf\u6d4e\u5b66\u5bb6\u8bf4\u67d0\u653f\u7b56\u957f\u671f\u6709\u5229\uff0c\u4f46\u77ed\u671f\u4f1a\u8ba9\u5f88\u591a\u4eba\u5931\u4e1a\u3002\n\n\u6bcf\u6b21\u8fd9\u6837\u7684\u51b2\u7a81\uff0c\u67cf\u62c9\u56fe\u7684\u95ee\u9898\u90fd\u5728\u56de\u54cd\uff1a\u8ba9\u770b\u5230\u771f\u5b9e\u7684\u4eba\u505a\u51b3\u5b9a\uff0c\u8fd8\u662f\u8ba9\u6240\u6709\u4eba\u4e00\u8d77\u9009\uff1f","Though philosopher kings sound remote, these questions are still alive today.\n\nClimate scientists say emissions must be cut, but voters won't bear the economic cost. Public health experts say lockdowns are necessary, but citizens oppose restrictions on freedom. Economists say a policy is beneficial long-term, but it will cost many people their jobs short-term.\n\nEvery time such conflicts arise, Plato's question echoes: should those who see the truth make the decisions, or should everyone choose together?",null,"","")
B.CG=new A.aR("\u6709\u3002\u6bcf\u4e2a\u4eba\u90fd\u6709\u5224\u65ad\u529b\uff0c\u53ea\u662f\u7a0b\u5ea6\u4e0d\u540c\u3002","Yes. Everyone has judgment \u2014 it's just a matter of degree.","node_2a")
B.D7=new A.aR("\u5927\u90e8\u5206\u65f6\u5019\u6ca1\u6709\u3002\u5f88\u591a\u4eba\u786e\u5b9e\u770b\u4e0d\u5230\u5168\u5c40\u3002","Most of the time, no. Many people truly can't see the big picture.","node_2b")
B.HG=A.a(s([B.CG,B.D7]),t.u)
B.Di=new A.bd("node_1","philosopher","\u4f60\u5df2\u7ecf\u770b\u5230\u4e86\u6211\u7684\u65b9\u6848\u3002\u90a3\u6211\u95ee\u4f60\uff1a\u4f60\u89c9\u5f97\u666e\u901a\u4eba\u6709\u80fd\u529b\u5224\u65ad\u4ec0\u4e48\u5bf9\u57ce\u90a6\u662f\u597d\u7684\u5417\uff1f","You've seen my proposal. So let me ask you: do you think ordinary people have the ability to judge what's good for the city-state?",B.HG,null,!1)
B.CF=new A.aR("\u627e\u6700\u597d\u7684\u533b\u751f\uff0c\u542c\u4ed6\u7684\u3002","Find the best doctor and follow their advice.","node_3aa")
B.Ct=new A.aR("\u95ee\u8eab\u8fb9\u7684\u4eba\uff0c\u7efc\u5408\u5927\u5bb6\u7684\u610f\u89c1\u3002","Ask the people around me and weigh everyone's opinions.","node_3ab")
B.J7=A.a(s([B.CF,B.Ct]),t.u)
B.Dz=new A.bd("node_2a","philosopher","\u4f60\u5bf9\u4eba\u7684\u4fe1\u5fc3\u8ba9\u6211\u60f3\u8d77\u5e74\u8f7b\u65f6\u7684\u81ea\u5df1\u3002\u4f46\u4f60\u8fd8\u8bb0\u5f97\u6d1e\u7a74\u5417\uff1f\u90a3\u4e9b\u56da\u5f92\u4e0d\u8822\uff0c\u4ed6\u4eec\u53ea\u662f\u4e00\u8f88\u5b50\u6ca1\u89c1\u8fc7\u9633\u5149\u3002\u4f60\u8ba9\u4e00\u4e2a\u4ece\u6ca1\u89c1\u8fc7\u5149\u7684\u4eba\u53bb\u63cf\u8ff0\u592a\u9633\uff0c\u4ed6\u80fd\u8bf4\u51fa\u4ec0\u4e48\uff1f\n\n\u6211\u6362\u4e2a\u65b9\u5f0f\u95ee\u3002\u5047\u8bbe\u4f60\u751f\u4e86\u91cd\u75c5\uff0c\u4f60\u4f1a\u600e\u4e48\u529e\uff1f","Your faith in people reminds me of my younger self. But do you remember the cave? Those prisoners aren't stupid \u2014 they've simply never seen sunlight. If you ask someone who's never seen light to describe the sun, what could they say?\n\nLet me put it differently. Suppose you fell seriously ill \u2014 what would you do?",B.J7,null,!1)
B.CI=new A.aR("\u6211\u53ef\u80fd\u4e5f\u5728\u6d1e\u7a74\u91cc\u3002","I'm probably in the cave too.","node_3ba")
B.Cr=new A.aR("\u6211\u81f3\u5c11\u6bd4\u5927\u591a\u6570\u4eba\u770b\u5f97\u66f4\u6e05\u695a\u3002","I can see more clearly than most, at least.","node_3bb")
B.HK=A.a(s([B.CI,B.Cr]),t.u)
B.DK=new A.bd("node_2b","philosopher","\u5f88\u597d\uff0c\u4f60\u6bd4\u5f88\u591a\u4eba\u8bda\u5b9e\u3002\u4f46\u6211\u60f3\u518d\u63a8\u4f60\u4e00\u6b65\u3002\u4f60\u8bf4\u5927\u591a\u6570\u4eba\u770b\u4e0d\u5230\u5168\u5c40\uff0c\u90a3\u4f60\u81ea\u5df1\u5462\uff1f\u4f60\u662f\u7ad9\u5728\u6d1e\u7a74\u5916\u9762\u7684\u4eba\uff0c\u8fd8\u662f\u53ea\u4e0d\u8fc7\u6bd4\u65c1\u8fb9\u7684\u56da\u5f92\u591a\u8f6c\u4e86\u4e00\u4e0b\u5934\uff1f","Good \u2014 you're more honest than most. But let me push you further. You say most people can't see the big picture. What about you? Are you standing outside the cave, or have you merely turned your head a bit more than the prisoner next to you?",B.HK,null,!1)
B.CK=new A.aR("\u4e0d\u4e00\u6837\u3002\u6cbb\u75c5\u6709\u5bf9\u9519\uff0c\u6cbb\u56fd\u6ca1\u6709\u6807\u51c6\u7b54\u6848\u3002","It's different. Medicine has right and wrong answers; governance doesn't have a standard answer.","node_4_democracy")
B.D1=new A.aR("\u4f60\u8bf4\u5f97\u5bf9\uff0c\u6211\u6ca1\u6cd5\u53cd\u9a73\u3002","You're right. I can't argue with that.","node_4_agree")
B.GN=A.a(s([B.CK,B.D1]),t.u)
B.Do=new A.bd("node_3aa","philosopher","\u4f60\u770b\uff0c\u4f60\u81ea\u5df1\u5c31\u8bc1\u660e\u4e86\u6211\u7684\u89c2\u70b9\u3002\u547d\u60ac\u4e00\u7ebf\u7684\u65f6\u5019\uff0c\u4f60\u4e0d\u4f1a\u53bb\u641e\u4ec0\u4e48\u6295\u7968\uff0c\u4f60\u4f1a\u53bb\u627e\u90a3\u4e2a\u771f\u6b63\u61c2\u7684\u4eba\u3002\u90a3\u6211\u95ee\u4f60\uff0c\u6cbb\u7406\u4e00\u4e2a\u57ce\u90a6\uff0c\u5343\u4e07\u4eba\u7684\u547d\u8fd0\uff0c\u96be\u9053\u4e0d\u6bd4\u6cbb\u4f60\u4e00\u4e2a\u4eba\u7684\u75c5\u66f4\u91cd\u5927\uff1f\u51ed\u4ec0\u4e48\u6cbb\u75c5\u8981\u542c\u884c\u5bb6\u7684\uff0c\u6cbb\u56fd\u53cd\u5012\u4eba\u4eba\u90fd\u80fd\u63d2\u5634\uff1f","See \u2014 you just proved my point. When your life is on the line, you don't hold a vote; you find someone who truly knows. So let me ask: governing a city-state, the fate of millions \u2014 isn't that far more significant than treating one person's illness? Why should medicine require an expert, but governance allow everyone to chime in?",B.GN,null,!1)
B.CL=new A.aR("\u90a3\u662f\u4e00\u6b21\u9519\u8bef\uff0c\u4e0d\u80fd\u56e0\u6b64\u5426\u5b9a\u6c11\u4e3b\u3002","That was a mistake. You can't reject democracy because of one error.","node_4_democracy")
B.Ci=new A.aR("\u8fd9\u786e\u5b9e\u52a8\u6447\u4e86\u6211\u3002","That does shake my conviction.","node_4_agree")
B.Ji=A.a(s([B.CL,B.Ci]),t.u)
B.DJ=new A.bd("node_3ab","philosopher","\u8fde\u547d\u90fd\u613f\u610f\u4ea4\u7ed9\u4f17\u4eba\u6765\u5b9a\uff0c\u4f60\u662f\u6211\u89c1\u8fc7\u6700\u5f7b\u5e95\u7684\u6c11\u4e3b\u4fe1\u5f92\u3002\u4f46\u6211\u5fc5\u987b\u544a\u8bc9\u4f60\u4e00\u4ef6\u4e8b\u3002\u96c5\u5178\uff0c\u6211\u7684\u57ce\u90a6\uff0c\u5b83\u7684\u6c11\u4e3b\u5236\u5ea6\u6295\u7968\u5904\u6b7b\u4e86\u82cf\u683c\u62c9\u5e95\u3002\u90a3\u662f\u6211\u8fd9\u8f88\u5b50\u9047\u5230\u8fc7\u6700\u597d\u7684\u4eba\u3002\u4e94\u767e\u4e2a\u4eba\u4e3e\u624b\uff0c\u591a\u6570\u4eba\u8bf4\u4ed6\u8be5\u6b7b\uff0c\u4ed6\u5c31\u559d\u4e0b\u4e86\u6bd2\u9152\u3002\n\n\u4f60\u73b0\u5728\u8fd8\u89c9\u5f97\u5927\u5bb6\u5546\u91cf\u7740\u6765\u603b\u662f\u9760\u8c31\u7684\uff1f","You'd even entrust your life to the crowd \u2014 you're the most thorough democrat I've ever met. But I must tell you something. Athens, my city-state, its democracy voted to execute Socrates. He was the best person I ever knew. Five hundred people raised their hands, the majority said he should die, and he drank the hemlock.\n\nDo you still think collective decision-making is always reliable?",B.Ji,null,!1)
B.Co=new A.aR("\u786e\u5b9e\u6ca1\u6cd5\u5224\u65ad\u3002\u54f2\u5b66\u738b\u65b9\u6848\u6709\u6839\u672c\u6f0f\u6d1e\u3002","Indeed, there's no way to judge. The philosopher king scheme has a fundamental flaw.","node_4_flaw")
B.CM=new A.aR("\u867d\u7136\u96be\u5224\u65ad\uff0c\u4f46\u603b\u6709\u4eba\u6bd4\u5176\u4ed6\u4eba\u66f4\u63a5\u8fd1\u771f\u7406\u3002","It's hard to judge, but some people are always closer to truth than others.","node_4_agree")
B.Ih=A.a(s([B.Co,B.CM]),t.u)
B.Dj=new A.bd("node_3ba","philosopher",'\uff08\u7b11\u4e86\uff09\u597d\u3002\u627f\u8ba4\u81ea\u5df1\u5728\u6d1e\u7a74\u91cc\uff0c\u8fd9\u9700\u8981\u52c7\u6c14\u3002\u82cf\u683c\u62c9\u5e95\u8bf4\u8fc7"\u6211\u77e5\u9053\u6211\u4e0d\u77e5\u9053"\uff0c\u4f60\u8eab\u4e0a\u6709\u4ed6\u7684\u5f71\u5b50\u3002\n\n\u4f46\u8fd9\u5c31\u9ebb\u70e6\u4e86\u3002\u5982\u679c\u4f60\u81ea\u5df1\u4e5f\u5728\u6d1e\u7a74\u91cc\uff0c\u4f60\u62ff\u4ec0\u4e48\u53bb\u5224\u65ad\u8c01\u662f\u90a3\u4e2a\u8d70\u51fa\u53bb\u7684\u4eba\uff1f\u4f60\u600e\u4e48\u77e5\u9053\u7ad9\u5728\u4f60\u9762\u524d\u7684\u54f2\u5b66\u738b\u662f\u771f\u7684\u770b\u89c1\u4e86\u592a\u9633\uff0c\u8fd8\u662f\u53e6\u4e00\u4e2a\u56da\u5f92\u5728\u5439\u725b\uff1f',"(Laughs) Good. Admitting you're in the cave takes courage. Socrates said \"I know that I know nothing\" \u2014 I see his shadow in you.\n\nBut this creates a problem. If you're also in the cave, how can you judge who has walked out? How do you know whether the philosopher king standing before you has truly seen the sun, or is just another prisoner boasting?",B.Ih,null,!1)
B.Cu=new A.aR("\u770b\u884c\u52a8\u548c\u7ed3\u679c\uff0c\u4e0d\u662f\u770b\u4ed6\u81ea\u5df1\u600e\u4e48\u8bf4\u3002","By actions and results, not by what someone claims about themselves.","node_4_practice")
B.CU=new A.aR("\u4e5f\u8bb8\u6839\u672c\u5206\u4e0d\u5f00\u3002\u8fd9\u6b63\u662f\u54f2\u5b66\u738b\u7684\u5371\u9669\u3002","Perhaps you can't tell them apart. That's precisely the danger of the philosopher king.","node_4_flaw")
B.IQ=A.a(s([B.Cu,B.CU]),t.u)
B.D8=new A.bd("node_3bb","philosopher","\u4f60\u5bf9\u81ea\u5df1\u5f88\u6709\u628a\u63e1\u3002\u4f46\u6211\u5728\u53d9\u62c9\u53e4\u89c1\u8fc7\u4e00\u4e2a\u4eba\uff0c\u5e74\u8f7b\u7684\u66b4\u541b\u72c4\u5965\u5c3c\u7d22\u65af\u4e8c\u4e16\uff0c\u4ed6\u4e5f\u89c9\u5f97\u81ea\u5df1\u6bd4\u6240\u6709\u4eba\u770b\u5f97\u6e05\u695a\u3002\u6211\u8fd9\u8f88\u5b50\u89c1\u8fc7\u7684\u6bcf\u4e00\u4e2a\u66b4\u541b\u90fd\u89c9\u5f97\u81ea\u5df1\u662f\u54f2\u5b66\u738b\u3002\n\n\u6240\u4ee5\u6211\u95ee\u4f60\uff0c\u771f\u6b63\u7684\u667a\u6167\u548c\u81ea\u4ee5\u4e3a\u662f\uff0c\u4f60\u600e\u4e48\u5206\u5f97\u5f00\uff1f","You're quite confident in yourself. But in Syracuse I met a man \u2014 the young tyrant Dionysius II \u2014 who also thought he could see more clearly than everyone. Every tyrant I've met in my life believed himself to be a philosopher king.\n\nSo I ask you: how do you distinguish genuine wisdom from mere self-assurance?",B.IQ,null,!1)
B.CB=new A.aR("\u613f\u610f\u3002\u8fd9\u4e2a\u4ee3\u4ef7\u6bd4\u628a\u6743\u529b\u4ea4\u7ed9\u4e00\u4e2a\u4eba\u5c0f\u3002","Yes. That cost is smaller than handing power to one person.","node_5_question")
B.Cj=new A.aR("\u4f60\u8bf4\u5f97\u6211\u6709\u70b9\u52a8\u6447\u4e86\u3002","You're starting to shake my conviction.","node_5_agree")
B.HX=A.a(s([B.CB,B.Cj]),t.u)
B.DB=new A.bd("node_4_democracy","philosopher","\u4f60\u660e\u660e\u770b\u5230\u4e86\u6c11\u4e3b\u7684\u88c2\u7f1d\uff0c\u4f46\u4f60\u8fd8\u662f\u9009\u5b83\u3002\u6211\u4e0d\u662f\u4e0d\u7406\u89e3\u4f60\u3002\u4f60\u9009\u6c11\u4e3b\uff0c\u8bf4\u5230\u5e95\u4e0d\u662f\u56e0\u4e3a\u76f8\u4fe1\u4f17\u4eba\u7684\u667a\u6167\uff0c\u662f\u56e0\u4e3a\u4f60\u4e0d\u6562\u628a\u547d\u8fd0\u4ea4\u7ed9\u4efb\u4f55\u4e00\u4e2a\u4eba\u3002\u8fd9\u662f\u6e05\u9192\uff0c\u4f46\u4e5f\u662f\u4e00\u79cd\u8ba4\u547d\u3002\n\n\u4f60\u613f\u610f\u63a5\u53d7\u8fd9\u4e2a\u4ee3\u4ef7\u5417\uff1f","You're stubborn. You clearly see the cracks in democracy, but you still choose it. I don't blame you. At the end of the day, you choose democracy not because you trust the wisdom of the crowd, but because you don't dare entrust your fate to any single person. That's clear-headed, but it's also a kind of resignation.\n\nAre you willing to accept that cost?",B.HX,null,!1)
B.D4=new A.aR("\u8ddf\u4e0d\u4e0a\u3002\u6709\u9053\u7406\u662f\u4e00\u56de\u4e8b\uff0c\u8ba9\u6211\u5b8c\u5168\u670d\u4ece\u662f\u53e6\u4e00\u56de\u4e8b\u3002","No. Agreeing in principle is one thing; complete submission is another.","node_5_question")
B.Cv=new A.aR("\u5982\u679c\u4ed6\u771f\u7684\u770b\u5230\u4e86\u5584\uff0c\u6211\u613f\u610f\u3002","If he has truly seen the Good, I'm willing.","node_5_agree")
B.HT=A.a(s([B.D4,B.Cv]),t.u)
B.Ds=new A.bd("node_4_agree","philosopher","\u4f60\u80fd\u8d70\u5230\u8fd9\u4e00\u6b65\uff0c\u6211\u5f88\u9ad8\u5174\u3002\u4f46\u6700\u96be\u7684\u90e8\u5206\u6765\u4e86\u3002\u4f60\u65e2\u7136\u627f\u8ba4\u6709\u4eba\u770b\u5f97\u6bd4\u4f60\u8fdc\uff0c\u90a3\u903b\u8f91\u4e0a\u53ea\u6709\u4e00\u6761\u8def\u3002\n\n\u4f60\u8981\u670d\u4ece\u4ed6\u3002\u4e0d\u662f\u8ddf\u4ed6\u5546\u91cf\uff0c\u4e0d\u662f\u7ed9\u4ed6\u63d0\u610f\u89c1\uff0c\u662f\u628a\u4f60\u7684\u5224\u65ad\u653e\u4e0b\uff0c\u542c\u4ed6\u7684\u3002\n\n\u4f60\u8fd8\u8ddf\u5f97\u4e0a\u5417\uff1f","I'm glad you've come this far. But here comes the hardest part. Since you admit someone can see further than you, logically there's only one path.\n\nYou must obey them. Not consult with them, not offer your opinions \u2014 set aside your judgment and follow theirs.\n\nCan you still follow?",B.HT,null,!1)
B.D5=new A.aR("\u6709\u3002\u7406\u60f3\u5c31\u50cf\u706f\u5854\uff0c\u8d70\u4e0d\u5230\u4e5f\u80fd\u7167\u8def\u3002","Yes. An ideal is like a lighthouse \u2014 you can't reach it, but it still lights the way.","node_5_agree")
B.CS=new A.aR("\u6ca1\u6709\u3002\u9020\u4e0d\u51fa\u6765\u7684\u4e1c\u897f\u60f3\u5b83\u5e72\u4ec0\u4e48\u3002","No. What's the point of imagining something that can never be built?","node_5_question")
B.H4=A.a(s([B.D5,B.CS]),t.u)
B.D9=new A.bd("node_4_flaw","philosopher","\u4f60\u6233\u4e2d\u4e86\u6700\u75bc\u7684\u5730\u65b9\u3002\u5982\u679c\u6ca1\u6709\u4eba\u80fd\u53ef\u9760\u5730\u8ba4\u51fa\u54f2\u5b66\u738b\uff0c\u6211\u7684\u6574\u5ea7\u57ce\u90a6\u5c31\u5efa\u5728\u6d41\u6c99\u4e0a\u3002\n\n\u6211\u53bb\u4e86\u4e09\u6b21\u53d9\u62c9\u53e4\uff0c\u4e09\u6b21\u90fd\u662f\u4e00\u8eab\u72fc\u72c8\u5730\u56de\u6765\u3002\u4e5f\u8bb8\u4f60\u662f\u5bf9\u7684\u3002\u4f46\u6211\u8fd8\u662f\u60f3\u95ee\u4f60\u4e00\u4e2a\u95ee\u9898\uff1a\u5c31\u7b97\u6c38\u8fdc\u9020\u4e0d\u51fa\u6765\uff0c\u77e5\u9053\u6700\u597d\u7684\u57ce\u90a6\u957f\u4ec0\u4e48\u6837\uff0c\u6709\u6ca1\u6709\u610f\u4e49\uff1f","You've hit the sorest spot. If no one can reliably identify the philosopher king, my entire city is built on sand.\n\nI went to Syracuse three times, and came back humiliated every time. Perhaps you're right. But I still want to ask you: even if it can never be built, is there value in knowing what the best city-state looks like?",B.H4,null,!1)
B.CH=new A.aR("\u90a3\u5c31\u628a\u68c0\u9a8c\u7684\u65f6\u95f4\u62c9\u957f\u3002","Then extend the evaluation period.","node_5_question")
B.Cw=new A.aR("\u4f60\u8bf4\u670d\u6211\u4e86\u3002\u7ed3\u679c\u786e\u5b9e\u4e0d\u662f\u597d\u6807\u51c6\u3002","You've convinced me. Results really aren't a good standard.","node_5_agree")
B.Hl=A.a(s([B.CH,B.Cw]),t.u)
B.Dl=new A.bd("node_4_practice","philosopher",'\u62ff\u7ed3\u679c\u8bf4\u8bdd\uff0c\u5f88\u5b9e\u5728\u3002\u4f46\u6211\u95ee\u4f60\uff1a\u5982\u679c\u54f2\u5b66\u738b\u63a8\u884c\u4e00\u4e2a\u653f\u7b56\uff0c\u8981\u4e8c\u5341\u5e74\u624d\u80fd\u89c1\u6548\uff0c\u4f46\u6c11\u4f17\u4e94\u5e74\u5c31\u5750\u4e0d\u4f4f\u4e86\uff0c\u4f60\u542c\u8c01\u7684\uff1f\n\n\u771f\u6b63\u770b\u5f97\u8fdc\u7684\u51b3\u5b9a\uff0c\u505a\u51fa\u6765\u7684\u5934\u51e0\u5e74\u5f80\u5f80\u662f\u6328\u9a82\u7684\u3002\u4f60\u9760"\u770b\u7ed3\u679c"\uff0c\u770b\u7684\u662f\u54ea\u4e00\u5e74\u7684\u7ed3\u679c\uff1f','Judging by results \u2014 very practical. But let me ask you: if a philosopher king enacts a policy that takes twenty years to bear fruit, but the public loses patience after five, who do you listen to?\n\nTruly far-sighted decisions are often criticized in their first years. When you "judge by results," which year\'s results are you looking at?',B.Hl,null,!1)
B.Dv=new A.bd("node_5_question","narrator","\u4e9a\u91cc\u58eb\u591a\u5fb7\uff1a\u8001\u5e08\uff0c\u5bb9\u6211\u8bf4\u4e00\u53e5\u3002\u770b\u8d77\u6765\u4f60\u8fd9\u4f4d\u670b\u53cb\u6ca1\u90a3\u4e48\u5bb9\u6613\u88ab\u8bf4\u52a8\u3002\n\n\u6211\u5012\u89c9\u5f97\u4ed6\u7684\u6000\u7591\u65b9\u5411\u662f\u5bf9\u7684\uff0c\u4e0d\u8fc7\u7406\u7531\u8fd8\u53ef\u4ee5\u66f4\u5145\u5206\u3002\u95ee\u9898\u4e0d\u53ea\u662f\u4fe1\u4e0d\u4fe1\u5f97\u8fc7\u54f2\u5b66\u738b\u3002\u95ee\u9898\u662f\uff0c\u628a\u8fd9\u4e48\u5927\u7684\u6743\u529b\u653e\u5728\u4efb\u4f55\u4e00\u4e2a\u4eba\u8eab\u4e0a\uff0c\u4e0d\u7ba1\u4ed6\u6709\u591a\u597d\uff0c\u672c\u8d28\u4e0a\u90fd\u662f\u4e00\u573a\u8c6a\u8d4c\u3002\u6cd5\u5f8b\u7b28\u4e00\u70b9\uff0c\u6162\u4e00\u70b9\uff0c\u4f46\u6cd5\u5f8b\u4e0d\u4f1a\u88ab\u6743\u529b\u5582\u5927\u4e86\u80c3\u53e3\u3002","Aristotle: Teacher, if I may. It seems your friend here isn't so easily swayed.\n\nI think his skepticism is in the right direction, though his reasoning could be stronger. The issue isn't just whether we can trust a philosopher king. The issue is that placing so much power in any single person, no matter how good, is fundamentally a gamble. The law may be clumsy and slow, but the law won't develop an appetite fed by power.",null,"node_5_question_plato",!1)
B.CX=new A.aR("\u6211\u66f4\u540c\u610f\u67cf\u62c9\u56fe\u3002\u7406\u60f3\u867d\u96be\u5b9e\u73b0\uff0c\u4f46\u6211\u4eec\u9700\u8981\u6700\u9ad8\u6807\u51c6\u3002","I agree more with Plato. Ideals may be hard to achieve, but we need the highest standard.","node_end")
B.Cm=new A.aR("\u6211\u66f4\u540c\u610f\u4e9a\u91cc\u58eb\u591a\u5fb7\u3002\u5236\u5ea6\u6bd4\u4f9d\u8d56\u67d0\u4e2a\u4eba\u53ef\u9760\u3002","I agree more with Aristotle. Institutions are more reliable than depending on any individual.","node_end")
B.mU=A.a(s([B.CX,B.Cm]),t.u)
B.Da=new A.bd("node_5_question_plato","philosopher","\u4f60\u603b\u662f\u8fd9\u6837\uff0c\u6211\u7684\u5b66\u751f\u3002\u4f60\u770b\u5230\u4e86\u811a\u4e0b\u7684\u571f\u5730\uff0c\u5374\u4e0d\u80af\u62ac\u5934\u770b\u5929\u4e0a\u7684\u661f\u661f\u3002","You always do this, my student. You see the ground beneath your feet, but refuse to look up at the stars.",B.mU,null,!1)
B.DG=new A.bd("node_5_agree","narrator","\u4e9a\u91cc\u58eb\u591a\u5fb7\uff1a\u8001\u5e08\uff0c\u5bb9\u6211\u8bf4\u4e00\u53e5\u3002\u4f60\u8fd9\u4f4d\u670b\u53cb\u4f3c\u4e4e\u88ab\u4f60\u8bf4\u670d\u4e86\uff0c\u4f46\u6709\u4e9b\u8bdd\u6211\u4e0d\u5f97\u4e0d\u8bb2\u3002\n\n\u6211\u8ddf\u7740\u4f60\u5b66\u4e86\u4e8c\u5341\u5e74\uff0c\u6211\u4ece\u6765\u6ca1\u89c1\u8fc7\u4ec0\u4e48\u7406\u578b\u4e16\u754c\u3002\u5982\u679c\u8fde\u6211\u90fd\u6ca1\u89c1\u8fc7\uff0c\u51ed\u4ec0\u4e48\u76f8\u4fe1\u4f60\u7684\u54f2\u5b66\u738b\u5c31\u4e00\u5b9a\u89c1\u8fc7\uff1f\u518d\u8bf4\u4e86\uff0c\u5c31\u7b97\u4ed6\u4eca\u5929\u770b\u5230\u4e86\u5584\uff0c\u6743\u529b\u8fd9\u4e2a\u4e1c\u897f\u4f1a\u6539\u53d8\u4eba\u3002\u4eca\u5929\u7684\u54f2\u5b66\u738b\uff0c\u4e09\u5e74\u540e\u53ef\u80fd\u5c31\u662f\u66b4\u541b\u3002\n\n\u6bd4\u8d77\u627e\u4e00\u4e2a\u5b8c\u7f8e\u7684\u4eba\uff0c\u4e0d\u5982\u82b1\u529b\u6c14\u5efa\u4e00\u5957\u8fc7\u5f97\u53bb\u7684\u5236\u5ea6\u3002\u6cd5\u5f8b\u4e0d\u5b8c\u7f8e\uff0c\u4f46\u6cd5\u5f8b\u4e0d\u4f1a\u53d8\u8d28\u3002","Aristotle: Teacher, if I may. Your friend here seems convinced, but there are things I must say.\n\nI studied under you for twenty years, and I never once saw any world of Forms. If even I haven't seen it, why should we trust that your philosopher king has? Besides, even if he sees the Good today, power changes people. Today's philosopher king could be tomorrow's tyrant.\n\nRather than searching for a perfect person, better to spend that effort building a decent system. The law isn't perfect, but the law won't corrupt.",null,"node_5_agree_plato",!1)
B.Dc=new A.bd("node_5_agree_plato","philosopher","\u4f60\u770b\u5230\u4e86\u811a\u4e0b\u7684\u571f\u5730\uff0c\u5374\u4e0d\u80af\u62ac\u5934\u770b\u5929\u4e0a\u7684\u661f\u661f\u3002\u4f60\u4ece\u6211\u8fd9\u91cc\u5b66\u5230\u4e86\u4e00\u5207\uff0c\u5374\u5426\u8ba4\u4e86\u6700\u91cd\u8981\u7684\u4e1c\u897f\u3002","You see the ground beneath your feet, but refuse to look up at the stars. You learned everything from me, yet you deny the most important thing.",B.mU,null,!1)
B.Dh=new A.bd("node_end","narrator","","",null,null,!0)
